arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_1cf9f12d9188493ba75615e67020e9d3.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        @foreach (var section in _sections)
        {
            <button class="sidebar-btn @(section == _activeSection ? "active" : "")"
                    @onclick="() => SelectSection(section)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

<!-- Toast notification -->
@if (_showToast)
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
        <span>@_toastMessage</span>
        <button class="toast-close" @onclick="() => _showToast = false">&times;</button>
    </div>
}

<!-- Session revoke confirmation dialog -->
@if (_showRevokeDialog)
{
    <div class="modal-backdrop" @onclick="() => _showRevokeDialog = false"></div>
    <div class="confirm-dialog">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
        <p class="text-muted">This will sign out the device immediately.</p>
        <div class="dialog-actions">
            <button class="btn btn-secondary" @onclick="() => _showRevokeDialog = false">Cancel</button>
            <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _showToast;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Notifications
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] AvailableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync("Profile");
    }

    private async Task SelectSection(string section)
    {
        if (_activeSection == section) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionDataAsync(section);
    }

    private async Task LoadSectionDataAsync(string section)
    {
        switch (section)
        {
            case "Profile":
                _savedProfile = await SettingsService.GetProfileAsync();
                ResetProfileFields();
                break;
            case "Notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _allChannels = ["announcements", "random", "off-topic", "watercooler", "design"];
                _mutedChannels = new HashSet<string>(prefs.MutedChannels);
                break;
            case "Security":
                _security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _security.TwoFactorEnabled;
                _passwordPanelOpen = false;
                _currentPassword = _newPassword = _confirmPassword = "";
                break;
            case "Appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
        _loading = false;
    }

    private void ResetProfileFields()
    {
        if (_savedProfile is null) return;
        _displayName = _savedProfile.DisplayName;
        _email = _savedProfile.Email;
        _bio = _savedProfile.Bio;
        _avatarUrl = _savedProfile.AvatarUrl;
    }

    // --- Profile ---

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges() => ResetProfileFields();

    // --- Notifications ---

    private void ToggleChannelMute(string channel)
    {
        if (!_mutedChannels.Remove(channel))
            _mutedChannels.Add(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // --- Security ---

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }
        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", isError: true);
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            _showRevokeDialog = false;
            _sessionToRevoke = null;
            await ShowToast("Session revoked.");
        }
    }

    // --- Appearance ---

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    // --- Helpers ---

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3500, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    // --- Render fragments ---

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>
            <p class="section-desc">Manage your personal information and public profile.</p>

            <div class="profile-top">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">No Avatar</div>
                    }
                    <div class="avatar-url-display" title="@_avatarUrl">@_avatarUrl</div>
                </div>

                <div class="profile-fields">
                    <div class="field-group">
                        <label for="displayName">Display Name</label>
                        <input id="displayName" type="text" class="form-control" @bind="_displayName" />
                    </div>
                    <div class="field-group">
                        <label for="email">Email</label>
                        <input id="email" type="email" class="form-control" @bind="_email" />
                    </div>
                    <div class="field-group">
                        <label for="bio">Bio</label>
                        <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                    </div>
                </div>
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>
            <p class="section-desc">Control how and when you receive notifications.</p>

            <div class="toggle-group">
                <label class="toggle-row">
                    <span>Email Notifications</span>
                    <span class="toggle-switch">
                        <input type="checkbox" @bind="_emailNotifications" />
                        <span class="toggle-slider"></span>
                    </span>
                </label>
                <label class="toggle-row">
                    <span>Push Notifications</span>
                    <span class="toggle-switch">
                        <input type="checkbox" @bind="_pushNotifications" />
                        <span class="toggle-slider"></span>
                    </span>
                </label>
                <label class="toggle-row">
                    <span>Weekly Digest</span>
                    <span class="toggle-switch">
                        <input type="checkbox" @bind="_weeklyDigest" />
                        <span class="toggle-slider"></span>
                    </span>
                </label>
            </div>

            <h5 class="mt-4">Channel Muting</h5>
            <p class="text-muted">Muted channels won't send you notifications.</p>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox" checked="@_mutedChannels.Contains(channel)"
                               @onchange="() => ToggleChannelMute(channel)" />
                        <span class="channel-name">#@channel</span>
                        @if (_mutedChannels.Contains(channel))
                        {
                            <span class="badge bg-secondary ms-auto">Muted</span>
                        }
                    </label>
                }
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h3>Security</h3>
            <p class="section-desc">Manage your account security and active sessions.</p>

            <!-- Change Password -->
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="panel-chevron @(_passwordPanelOpen ? "open" : "")">▶</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="panel-body">
                        <div class="field-group">
                            <label for="currentPwd">Current Password</label>
                            <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="field-group">
                            <label for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="field-group">
                            <label for="confirmPwd">Confirm New Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning mt-2" @onclick="UpdatePassword">Update Password</button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="tfa-section">
                <div class="tfa-info">
                    <h5>Two-Factor Authentication</h5>
                    <span class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted mt-2">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }

            <!-- Active Sessions -->
            <h5 class="mt-4">Active Sessions</h5>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session == _security.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-success ms-2">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => RequestRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions found.</p>
            }
        </section>
    };

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Appearance</h3>
            <p class="section-desc">Customize the look and feel of your application.</p>

            <!-- Theme -->
            <div class="appearance-group">
                <h5>Theme</h5>
                <div class="radio-group">
                    @foreach (var t in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-option @(_theme == t ? "selected" : "")">
                            <input type="radio" name="theme" value="@t" checked="@(_theme == t)"
                                   @onchange="() => _theme = t" />
                            <span>@t</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="appearance-group">
                <h5>Font Size</h5>
                <div class="radio-group">
                    @foreach (var fs in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-option @(_fontSize == fs ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@fs" checked="@(_fontSize == fs)"
                                   @onchange="() => _fontSize = fs" />
                            <span>@fs</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="appearance-group">
                <h5>Language</h5>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in AvailableLanguages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="appearance-group">
                <label class="toggle-row">
                    <span><strong>Compact Mode</strong></span>
                    <span class="toggle-switch">
                        <input type="checkbox" @bind="_compactMode" />
                        <span class="toggle-slider"></span>
                    </span>
                </label>
            </div>

            <!-- Live Preview -->
            <div class="appearance-group">
                <h5>Preview</h5>
                <div class="live-preview @(_theme == "Dark" ? "preview-dark" : "preview-light")"
                     style="font-size: @GetPreviewFontSize(); @(_compactMode ? "padding: 0.75rem; line-height: 1.3;" : "")">
                    <div class="preview-header">
                        <strong>Sample Dashboard</strong>
                        <span class="preview-badge">@_theme Theme</span>
                    </div>
                    <p class="preview-text">
                        This is how your content will look with the selected settings.
                        Font size is set to <em>@_fontSize</em>, language is <em>@_language</em>,
                        and compact mode is <em>@(_compactMode ? "on" : "off")</em>.
                    </p>
                    <div class="preview-items">
                        <div class="preview-card">📊 Analytics</div>
                        <div class="preview-card">📁 Projects</div>
                        <div class="preview-card">💬 Messages</div>
                    </div>
                </div>
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}

