                        Font size is set to <em>@_fontSize</em>, language is <em>@_language</em>,
                        and compact mode is <em>@(_compactMode ? "on" : "off")</em>.
                    </p>
                    <div class="preview-items">
                        <div class="preview-card">📊 Analytics</div>
                        <div class="preview-card">📁 Projects</div>
                        <div class="preview-card">💬 Messages</div>
                    </div>
                </div>
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}
