toolArgs.file_text:
/* ===== Settings Layout ===== */
.settings-layout {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    border: 1px solid #e0e0e0;
}

/* ===== Sidebar ===== */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #fff;
    border-right: 1px solid #e0e0e0;
    padding: 1.5rem 0;
    display: flex;
    flex-direction: column;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 700;
    color: #333;
    font-size: 1.1rem;
}

.sidebar-btn {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #555;
    cursor: pointer;
    transition: all 0.15s ease;
    width: 100%;
}

.sidebar-btn:hover {
    background: #f0f4ff;
    color: #1a73e8;
}

.sidebar-btn.active {
    background: #e8f0fe;
    color: #1a73e8;
    font-weight: 600;
    border-right: 3px solid #1a73e8;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* ===== Content ===== */
.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    overflow-y: auto;
    background: #fff;
}

.settings-section h3 {
    font-weight: 700;
    margin-bottom: 0.25rem;
}

.section-desc {
    color: #666;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 200px;
}

/* ===== Profile ===== */
.profile-top {
    display: flex;
    gap: 2rem;
    margin-bottom: 1.5rem;
}

.avatar-preview {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    min-width: 150px;
}

.avatar-img {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #e0e0e0;
}

.avatar-placeholder {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    background: #e8e8e8;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
}

.avatar-url-display {
    font-size: 0.75rem;
    color: #888;
    max-width: 150px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.profile-fields {
    flex: 1;
}

/* ===== Field groups ===== */
.field-group {
    margin-bottom: 1rem;
}

.field-group label {
    display: block;
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 0.3rem;
    color: #444;
}

.field-group .form-control {
    border-radius: 6px;
}

/* ===== Toggle switches ===== */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.85rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    border-radius: 24px;
    transition: 0.2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background-color: #fff;
    border-radius: 50%;
    transition: 0.2s;
}

.toggle-switch input:checked + .toggle-slider {
    background-color: #1a73e8;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(20px);
}

/* ===== Channel list ===== */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 0.75rem;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.1s;
}

.channel-item:hover {
    background: #f5f5f5;
}

.channel-item input[type="checkbox"] {
    accent-color: #1a73e8;
    width: 16px;
    height: 16px;
}

.channel-name {
    font-family: monospace;
    font-size: 0.95rem;
}

/* ===== Expandable panel ===== */
.expandable-panel {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    margin-bottom: 1.25rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    border: none;
    background: #fafafa;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 600;
    transition: background 0.1s;
}

.panel-header:hover {
    background: #f0f0f0;
}

.panel-chevron {
    font-size: 0.7rem;
    transition: transform 0.2s;
}

.panel-chevron.open {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #e0e0e0;
}

/* ===== Two-Factor ===== */
.tfa-section {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.tfa-info {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.tfa-info h5 {
    margin: 0;
}

.status-indicator {
    font-size: 0.8rem;
    padding: 0.2rem 0.6rem;
    border-radius: 12px;
    font-weight: 600;
}

.status-on {
    background: #d4edda;
    color: #155724;
}

.status-off {
    background: #f8d7da;
    color: #721c24;
}

/* ===== Sessions table ===== */
.sessions-table {
    margin-top: 0.5rem;
}

.sessions-table th {
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #888;
    font-weight: 600;
    border-bottom-width: 2px;
}

/* ===== Appearance ===== */
.appearance-group {
    margin-bottom: 1.5rem;
}

.appearance-group h5 {
    margin-bottom: 0.6rem;
    font-weight: 600;
}

.radio-group {
    display: flex;
    gap: 0.75rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 2px solid #e0e0e0;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.15s;
    font-size: 0.95rem;
}

.radio-option:hover {
    border-color: #aac8f7;
}

.radio-option.selected {
    border-color: #1a73e8;
    background: #e8f0fe;
}

.radio-option input[type="radio"] {
    accent-color: #1a73e8;
}

.appearance-group .form-select {
    max-width: 250px;
    border-radius: 6px;
}

/* ===== Live Preview ===== */
.live-preview {
    border: 1px solid #ddd;
    border-radius: 10px;
    padding: 1.25rem;
    transition: all 0.25s ease;
}

.preview-light {
    background: #fff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border-radius: 6px;
    background: #e8f0fe;
    color: #1a73e8;
}

.preview-dark .preview-badge {
    background: #2a2a3e;
    color: #7aa2f7;
}

.preview-text {
    margin-bottom: 0.75rem;
    line-height: 1.6;
}

.preview-items {
    display: flex;
    gap: 0.75rem;
}

.preview-card {
    padding: 0.6rem 1rem;
    border-radius: 8px;
    background: #f0f4ff;
    font-size: 0.9em;
}

.preview-dark .preview-card {
    background: #2a2a3e;
}

/* ===== Section actions ===== */
.section-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
    padding-top: 1.25rem;
    border-top: 1px solid #eee;
}

/* ===== Toast ===== */
.settings-toast {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    padding: 0.75rem 1.25rem;
    border-radius: 8px;
    display: flex;
    align-items: center;
    gap: 1rem;
    font-weight: 500;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
    z-index: 9999;
    animation: toast-slide-in 0.3s ease;
}

.toast-success {
    background: #d4edda;
