+    border-color: #1a73e8;
+    background: #e8f0fe;
+}
+
+.radio-option input[type="radio"] {
+    accent-color: #1a73e8;
+}
+
+.appearance-group .form-select {
+    max-width: 250px;
+    border-radius: 6px;
+}
+
+/* ===== Live Preview ===== */
+.live-preview {
+    border: 1px solid #ddd;
+    border-radius: 10px;
+    padding: 1.25rem;
+    transition: all 0.25s ease;
+}
+
+.preview-light {
+    background: #fff;
+    color: #333;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #e0e0e0;
+    border-color: #444;
+}
+
+.preview-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 0.75rem;
+}
+
+.preview-badge {
+    font-size: 0.75rem;
+    padding: 0.2rem 0.5rem;
+    border-radius: 6px;
+    background: #e8f0fe;
+    color: #1a73e8;
+}
+
+.preview-dark .preview-badge {
+    background: #2a2a3e;
+    color: #7aa2f7;
+}
+
+.preview-text {
+    margin-bottom: 0.75rem;
+    line-height: 1.6;
+}
+
+.preview-items {
+    display: flex;
+    gap: 0.75rem;
+}
+
+.preview-card {
+    padding: 0.6rem 1rem;
+    border-radius: 8px;
+    background: #f0f4ff;
+    font-size: 0.9em;
+}
+
+.preview-dark .preview-card {
+    background: #2a2a3e;
+}
+
+/* ===== Section actions ===== */
+.section-actions {
+    display: flex;
+    gap: 0.75rem;
+    margin-top: 1.5rem;
+    padding-top: 1.25rem;
+    border-top: 1px solid #eee;
+}
+
+/* ===== Toast ===== */
+.settings-toast {
+    position: fixed;
+    bottom: 1.5rem;
+    right: 1.5rem;
+    padding: 0.75rem 1.25rem;
+    border-radius: 8px;
+    display: flex;
+    align-items: center;
+    gap: 1rem;
+    font-weight: 500;
+    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
+    z-index: 9999;
+    animation: toast-slide-in 0.3s ease;
+}
+
+.toast-success {
+    background: #d4edda;
+    color: #155724;
+    border: 1px solid #c3e6cb;
+}
+
+.toast-error {
+    background: #f8d7da;
+    color: #721c24;
+    border: 1px solid #f5c6cb;
+}
+
+.toast-close {
+    background: none;
+    border: none;
+    font-size: 1.2rem;
+    cursor: pointer;
+    color: inherit;
+    line-height: 1;
+}
+
+@keyframes toast-slide-in {
+    from {
+        transform: translateY(20px);
+        opacity: 0;
+    }
+    to {
+        transform: translateY(0);
+        opacity: 1;
+    }
+}
+
+/* ===== Confirmation dialog ===== */
+.modal-backdrop {
+    position: fixed;
+    inset: 0;
+    background: rgba(0, 0, 0, 0.4);
+    z-index: 10000;
+}
+
+.confirm-dialog {
+    position: fixed;
+    top: 50%;
+    left: 50%;
+    transform: translate(-50%, -50%);
+    background: #fff;
+    border-radius: 12px;
+    padding: 1.5rem 2rem;
+    min-width: 380px;
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
+    z-index: 10001;
+}
+
+.confirm-dialog h5 {
+    margin-bottom: 0.75rem;
+}
+
+.dialog-actions {
+    display: flex;
+    justify-content: flex-end;
+    gap: 0.5rem;
+    margin-top: 1.25rem;
+}
+
